// MARK: - Keychain

final class Keychain {
    static let shared = Keychain()
    private init() {}

    func set(_ value: Data, for key: String) -> Bool {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: key
        ]
        SecItemDelete(query as CFDictionary)
        let add: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: key,
            kSecValueData as String: value,
            kSecAttrAccessible as String: kSecAttrAccessibleAfterFirstUnlockThisDeviceOnly
        ]
        return SecItemAdd(add as CFDictionary, nil) == errSecSuccess
    }

    func get(_ key: String) -> Data? {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: key,
            kSecReturnData as String: true,
            kSecMatchLimit as String: kSecMatchLimitOne
        ]
        var item: CFTypeRef?
        let status = SecItemCopyMatching(query as CFDictionary, &item)
        guard status == errSecSuccess else { return nil }
        return item as? Data
    }

    func delete(_ key: String) {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: key
        ]
        SecItemDelete(query as CFDictionary)
    }
}

// MARK: - Secure API Client (HMAC + TLS + optional pinning)

struct APIConfig {
    var baseURL: URL
    var apiKey: String
    var apiSecret: String
    var pinnedSPKISHA256: String? // base64 of SHA256(SPKI DER)
}

final class PinnedSessionDelegate: NSObject, URLSessionDelegate {
    let pinnedSPKISHA256: String?

    init(pinnedSPKISHA256: String?) {
        self.pinnedSPKISHA256 = pinnedSPKISHA256
        super.init()
    }

    func urlSession(_ session: URLSession, didReceive challenge: URLAuthenticationChallenge, completionHandler: @escaping (URLSession.AuthChallengeDisposition, URLCredential?) -> Void) {
        guard let pinned = pinnedSPKISHA256 else {
            completionHandler(.performDefaultHandling, nil)
            return
        }
        guard challenge.protectionSpace.authenticationMethod == NSURLAuthenticationMethodServerTrust,
              let trust = challenge.protectionSpace.serverTrust else {
            completionHandler(.performDefaultHandling, nil)
            return
        }

        var error: CFError?
        guard SecTrustEvaluateWithError(trust, &error) else {
            completionHandler(.cancelAuthenticationChallenge, nil)
            return
        }

        guard let cert = SecTrustGetCertificateAtIndex(trust, 0),
              let key = SecCertificateCopyKey(cert),
              let keyData = SecKeyCopyExternalRepresentation(key, nil) as Data? else {
            completionHandler(.cancelAuthenticationChallenge, nil)
            return
        }

        let hash = SHA256.hash(data: keyData)
        let b64 = Data(hash).base64EncodedString()

        if b64 == pinned {
            completionHandler(.useCredential, URLCredential(trust: trust))
        } else {
            completionHandler(.cancelAuthenticationChallenge, nil)
        }
    }
}

enum APIError: Error, LocalizedError {
    case invalidResponse
    case http(Int, String)
    case decoding(String)
    case encoding(String)
    case network(String)

    var errorDescription: String? {
        switch self {
        case .invalidResponse: return "Invalid response."
        case .http(let code, let msg): return "HTTP \(code): \(msg)"
        case .decoding(let msg): return "Decoding error: \(msg)"
        case .encoding(let msg): return "Encoding error: \(msg)"
        case .network(let msg): return "Network error: \(msg)"
        }
    }
}

final class APIClient {
    private let config: APIConfig
    private let session: URLSession
    private let encoder: JSONEncoder
    private let decoder: JSONDecoder

    init(config: APIConfig) {
        self.config = config
        let delegate = PinnedSessionDelegate(pinnedSPKISHA256: config.pinnedSPKISHA256)
        let cfg = URLSessionConfiguration.ephemeral
        cfg.waitsForConnectivity = true
        cfg.timeoutIntervalForRequest = 20
        cfg.timeoutIntervalForResource = 30
        cfg.httpAdditionalHeaders = [
            "Accept": "application/json",
            "Content-Type": "application/json"
        ]
        self.session = URLSession(configuration: cfg, delegate: delegate, delegateQueue: nil)
        self.encoder = JSONEncoder()
        self.encoder.dateEncodingStrategy = .iso8601
        self.decoder = JSONDecoder()
        self.decoder.dateDecodingStrategy = .iso8601
    }

    private func iso8601Now() -> String {
        ISO8601DateFormatter().string(from: Date())
    }

    private func sign(method: String, path: String, timestamp: String, body: Data?) -> String {
        let bodyHash = SHA256.hash(data: body ?? Data())
        let bodyHashHex = bodyHash.compactMap { String(format: "%02x", $0) }.joined()
        let canonical = "\(method.uppercased())\n\(path)\n\(timestamp)\n\(bodyHashHex)"
        let key = SymmetricKey(data: Data(config.apiSecret.utf8))
        let sig = HMAC<SHA256>.authenticationCode(for: Data(canonical.utf8), using: key)
        return Data(sig).base64EncodedString()
    }

    private func request(_ method: String, _ path: String, query: [URLQueryItem] = [], body: Data? = nil) throws -> URLRequest {
        var comps = URLComponents(url: config.baseURL.appendingPathComponent(path), resolvingAgainstBaseURL: false)!
        if !query.isEmpty { comps.queryItems = query }
        guard let url = comps.url else { throw APIError.network("Bad URL") }
        var req = URLRequest(url: url)
        req.httpMethod = method
        req.httpBody = body

        let ts = iso8601Now()
        let sig = sign(method: method, path: path, timestamp: ts, body: body)

        req.setValue(config.apiKey, forHTTPHeaderField: "X-API-KEY")
        req.setValue(ts, forHTTPHeaderField: "X-TS")
        req.setValue(sig, forHTTPHeaderField: "X-SIGNATURE")
        return req
    }

    func get<T: Decodable>(_ path: String, query: [URLQueryItem] = []) async throws -> T {
        let req = try request("GET", path, query: query, body: nil)
        return try await perform(req)
    }

    func post<T: Decodable, U: Encodable>(_ path: String, body: U) async throws -> T {
        let data: Data
        do { data = try encoder.encode(body) } catch { throw APIError.encoding(error.localizedDescription) }
        let req = try request("POST", path, body: data)
        return try await perform(req)
    }

    func delete<T: Decodable>(_ path: String) async throws -> T {
        let req = try request("DELETE", path, body: nil)
        return try await perform(req)
    }

    private func perform<T: Decodable>(_ req: URLRequest) async throws -> T {
        do {
            let (data, resp) = try await session.data(for: req)
            guard let http = resp as? HTTPURLResponse else { throw APIError.invalidResponse }
            if !(200...299).contains(http.statusCode) {
                let msg = String(data: data, encoding: .utf8) ?? "Unknown error"
                throw APIError.http(http.statusCode, msg)
            }
            do {
                return try decoder.decode(T.self, from: data)
            } catch {
                let raw = String(data: data, encoding: .utf8) ?? ""
                throw APIError.decoding("\(error.localizedDescription)\n\(raw)")
            }
        } catch let e as APIError {
            throw e
        } catch {
            throw APIError.network(error.localizedDescription)
        }
    }
}

// MARK: - Mock Trading Engine (for rapid deployment / offline demo)

final class MockTradingEngine {
    struct State: Codable {
        var cash: Double
        var positions: [String: Position]
        var lastPrices: [String: Double]
        var dayStartEquity: Double
        var updatedAt: Date
    }

    private let queue = DispatchQueue(label: "mock.engine.queue", qos: .userInitiated)
    private var state: State
    private var timer: DispatchSourceTimer?

    init(initialCash: Double = 100_000) {
        let symbols = ["AAPL","MSFT","NVDA","TSLA","AMZN","GOOGL","META","SPY","QQQ","AMD","NFLX","JPM"]
        var last: [String: Double] = [:]
        for s in symbols {
            last[s] = Double.random(in: 50...500) * (s == "SPY" || s == "QQQ" ? 1.0 : 1.0)
        }
        self.state = State(
            cash: initialCash,
            positions: [:],
            lastPrices: last,
            dayStartEquity: initialCash,
            updatedAt: Date()
        )
    }

    func startStreaming(_ onQuote: @escaping (Quote) -> Void) {
        stopStreaming()
        let t = DispatchSource.makeTimerSource(queue: queue)
        t.schedule(deadline: .now(), repeating: .milliseconds(350), leeway: .milliseconds(50))
        t.setEventHandler { [weak self] in
            guard let self else { return }
            let symbols = Array(self.state.lastPrices.keys)
            guard let sym = symbols.randomElement(), let last = self.state.lastPrices[sym] else { return }
            let drift = Double.random(in: -1.0...1.0) * max(0.05, last * 0.002)
            let newLast = max(0.01, last + drift)
            self.state.lastPrices[sym] = newLast
            self.state.updatedAt = Date()

            let spread = max(0.01, newLast * 0.0008)
            let bid = newLast - spread/2
            let ask = newLast + spread/2
            let change = newLast - last
            let changePct = last == 0 ? 0 : change/last

            let q = Quote(symbol: sym, bid: bid, ask: ask, last: newLast, change: change, changePct: changePct, timestamp: Date())
            onQuote(q)
        }
        self.timer = t
        t.resume()
    }

    func stopStreaming() {
        timer?.cancel()
        timer = nil
    }

    func snapshotPortfolio() -> PortfolioSnapshot {
        queue.sync {
            let positions = Array(state.positions.values).sorted { $0.symbol < $1.symbol }.map { pos in
                var p = pos
                p.marketPrice = state.lastPrices[p.symbol] ?? p.marketPrice
                return p
            }
            let equity = state.cash + positions.reduce(0) { $0 + $1.marketValue }
            let dayPnL = equity - state.dayStartEquity
            return PortfolioSnapshot(cash: state.cash, equity: equity, dayPnL: dayPnL, positions: positions, updatedAt: state.updatedAt)
        }
    }

    func quote(for symbol: String) -> Quote? {
        queue.sync {
            guard let last = state.lastPrices[symbol] else { return nil }
            let spread = max(0.01, last * 0.0008)
            let bid = last - spread/2
            let ask = last + spread/2
            return Quote(symbol: symbol, bid: bid, ask: ask, last: last, change: 0, changePct: 0, timestamp: Date())
        }
    }

    func execute(_ req: TradeRequest) -> TradeResponse {
        queue.sync {
            let symbol = req.symbol.uppercased()
            let q = quote(for: symbol) ?? Quote(symbol: symbol, bid: 0, ask: 0, last: 0, change: 0, changePct: 0, timestamp: Date())
            let fillPrice: Double
            switch req.type {
            case .market:
                fillPrice = (req.side == .buy) ? q.ask : q.bid
            case .limit:
                let lp = req.limitPrice ?? q.last
                if req.side == .buy {
                    fillPrice = min(lp, q.ask)
                } else {
                    fillPrice = max(lp, q.bid)
                }
            }

            let qty = max(0, req.quantity)
            let notional = qty * fillPrice
            var status: OrderStatus = .filled

            if qty <= 0 || fillPrice <= 0 {
                status = .rejected
            } else {
                if req.side == .buy {
                    if state.cash + 1e-9 < notional {
                        status = .rejected
                    } else {
                        state.cash -= notional
                        var pos = state.positions[symbol] ?? Position(symbol: symbol, quantity: 0, avgCost: 0, marketPrice: q.last)
                        let newQty = pos.quantity + qty
                        let newCost = (pos.avgCost * pos.quantity + fillPrice * qty) / max(1e-9, newQty)
                        pos.quantity = newQty
                        pos.avgCost = newCost
                        pos.marketPrice = state.lastPrices[symbol] ?? q.last
                        state.positions[symbol] = pos
                    }
                } else {
                    let held = state.positions[symbol]?.quantity ?? 0
                    if held + 1e-9 < qty {
                        status = .rejected
                    } else {
                        state.cash += notional
                        var pos = state.positions[symbol]!
                        pos.quantity -= qty
                        pos.marketPrice = state.lastPrices[symbol] ?? q.last
                        if pos.quantity <= 1e-9 {
                            state.positions.removeValue(forKey: symbol)
                        } else {
                            state.positions[symbol] = pos
                        }
                    }
                }
            }

            state.updatedAt = Date()
            let order = Order(
                id: UUID().uuidString,
                symbol: symbol,
                side: req.side,
                type: req.type,
                quantity: qty,
                limitPrice: req.limitPrice,
                status: status,
                filledQty: status == .filled ? qty : 0,
                avgFillPrice: status == .filled ? fillPrice : nil,
                createdAt: Date()
            )
            let snap = snapshotPortfolio()
            return TradeResponse(order: order, portfolio: snap)
        }
    }
}

// MARK: - App State

@MainActor
final class TradingStore: ObservableObject {
    @Published var watchlist: Watchlist = Watchlist(symbols: ["AAPL","MSFT","NVDA","TSLA","AMZN","SPY","QQQ"])
    @Published var quotes: [String: Quote] = [:]
    @Published var portfolio: PortfolioSnapshot = PortfolioSnapshot(cash: 100_000, equity: 100_000, dayPnL: 0, positions: [], updatedAt: Date())
    @Published var orders: [Order] = []
    @Published var isStreaming: Bool = false
    @Published var lastError: String? = nil
    @Published var isUsingMock: Bool = true

    private var engine = MockTradingEngine()
    private var cancellables = Set<AnyCancellable>()

    // Optional real API client (not used by default)
    private var apiClient: APIClient?

    func configureAPI(baseURL: URL, apiKey: String, apiSecret: String, pinnedSPKISHA256: String? = nil) {
        let cfg = APIConfig(baseURL: baseURL, apiKey: apiKey, apiSecret: apiSecret, pinnedSPKISHA256: pinnedSPKISHA256)
        self.apiClient = APIClient(config: cfg)
        self.isUsingMock = false
    }

    func useMock() {
        self.apiClient = nil
        self.isUsingMock = true
    }

    func start() {
        refreshPortfolio()
        startStreaming()
    }

    func startStreaming() {
        guard !isStreaming else { return }
        isStreaming = true
        if isUsingMock {
            engine.startStreaming { [weak self] q in
                Task { @MainActor in
                    self?.quotes[q.symbol] = q
                    self?.updatePositionsMarketPrice(symbol: q.symbol, price: q.last)
                }
            }
        } else {
            // Placeholder: real streaming would be via WebSocket; keep UI responsive by polling quotes.
            Task { await pollQuotesLoop() }
        }
    }

    func stopStreaming() {
        isStreaming = false
        engine.stopStreaming()
    }

    private func updatePositionsMarketPrice(symbol: String, price: Double) {
        var p = portfolio
        var changed = false
        for i in p.positions.indices {
            if p.positions[i].symbol == symbol {
                p.positions[i].marketPrice = price
                changed = true
            }
        }
        if changed {
            p.equity = p.cash + p.positions.reduce(0) { $0 + $1.marketValue }
            p.updatedAt = Date()
            portfolio = p
        }
    }

    func refreshPortfolio() {
        if isUsingMock {
            portfolio = engine.snapshotPortfolio()
        } else {
            Task {
                do {
                    guard let apiClient else { return }
                    let snap: PortfolioSnapshot = try await apiClient.get("/v1/portfolio")
                    await MainActor.run { self.portfolio = snap }
                } catch {
                    await MainActor.run { self.lastError = error.localizedDescription }
                }
            }
        }
    }

    func placeOrder(_ req: TradeRequest) {
        lastError = nil
        if isUsingMock {
            let resp = engine.execute(req)
            orders.insert(resp.order, at: 0)
            portfolio = resp.portfolio
        } else {
            Task {
                do {
                    guard let apiClient else { return }
                    let resp: TradeResponse = try await apiClient.post("/v1/trade", body: req)
                    await MainActor.run {
                        self.orders.insert(resp.order, at: 0)
                        self.portfolio = resp.portfolio
                    }
                } catch {
                    await MainActor.run { self.lastError = error.localizedDescription }
                }
            }
        }
    }

    func addSymbol(_ symbol: String) {
        let s = symbol.uppercased().trimmingCharacters(in: .whitespacesAndNewlines)
        guard !s.isEmpty else { return }
        guard !watchlist.symbols.contains(s) else { return }
        watchlist.symbols.insert(s, at: 0)
    }

    func removeSymbols(at offsets: IndexSet) {
        watchlist.symbols.remove(atOffsets: offsets)
    }

    func quoteFor(_ symbol: String) -> Quote? {
        if let q = quotes[symbol] { return q }
        if isUsingMock { return engine.quote(for: symbol) }
        return nil
    }

    private func pollQuotesLoop() async {
        while isStreaming && !isUsingMock {
            do {
                guard let apiClient else { break }
                let items = watchlist.symbols.map { URLQueryItem(name: "symbols", value: $0) }
                let list: [Quote] = try await apiClient.get("/v1/quotes", query: items)
                await MainActor.run {
                    for q in list { self.quotes[q.symbol] = q }
                }
            } catch {
                await MainActor.run { self.lastError = error.localizedDescription }
            }
            try? await Task.sleep(nanoseconds: 900_000_000)
        }
    }
}

// MARK: - Formatting

extension Double {
    func asMoney() -> String {
        let f = NumberFormatter()
        f.numberStyle = .currency
        f.currencyCode = "USD"
        f.maximumFractionDigits = 2
        f.minimumFractionDigits = 2
        return f.string(from: NSNumber(value: self)) ?? "$0.00"
    }

    func asPct() -> String {
        let f = NumberFormatter()
        f.numberStyle = .percent
        f.maximumFractionDigits = 2
        f.minimumFractionDigits = 2
        return f.string(from: NSNumber(value: self)) ?? "0.00%"
    }

    func asQty() -> String {
        let f = NumberFormatter()
        f.numberStyle = .decimal
        f.maximumFractionDigits = 6
        f.minimumFractionDigits = 0
        return f.string(from: NSNumber(value: self)) ?? "0"
    }
}

