    @State private var confirm: Bool = false

    private var quote: Quote? { store.quoteFor(symbol) }

    private var qty: Double { Double(quantityText.replacingOccurrences(of: ",", with: ".")) ?? 0 }
    private var limitPrice: Double? {
        let t = limitPriceText.trimmingCharacters(in: .whitespacesAndNewlines)
        if t.isEmpty { return nil }
        return Double(t.replacingOccurrences(of: ",", with: ".")) ?? nil
    }

    private var estPrice: Double {
        guard let q = quote else { return 0 }
        switch type {
        case .market:
            return side == .buy ? q.ask : q.bid
        case .limit:
            return limitPrice ?? q.last
        }
    }

    private var estNotional: Double { max(0, qty) * max(0, estPrice) }

    var body: some View {
        NavigationStack {
            Form {
                Section {
                    HStack {
                        VStack(alignment: .leading, spacing: 4) {
                            Text(symbol).font(.title2).bold()
                            if let q = quote {
                                Text("Last \(q.last.asMoney())  •  Bid \(q.bid.asMoney())  Ask \(q.ask.asMoney())")
                                    .font(.caption)
                                    .foregroundStyle(.secondary)
                            } else {
                                Text("Fetching quote…")
                                    .font(.caption)
                                    .foregroundStyle(.secondary)
                            }
                        }
                        Spacer()
                    }
                }

                Section("Order") {
                    Picker("Side", selection: $side) {
                        ForEach(OrderSide.allCases) { s in
                            Text(s.rawValue).tag(s)
                        }
                    }
                    .pickerStyle(.segmented)

                    Picker("Type", selection: $type) {
                        ForEach(OrderType.allCases) { t in
                            Text(t.rawValue).tag(t)
                        }
                    }
                    .pickerStyle(.segmented)

                    TextField("Quantity", text: $quantityText)
                        .keyboardType(.decimalPad)

                    if type == .limit {
                        TextField("Limit price", text: $limitPriceText)
                            .keyboardType(.decimalPad)
                    }
                }

                Section("Estimate") {
                    HStack {
                        Text("Est. price")
                        Spacer()
                        Text(estPrice.asMoney()).monospacedDigit()
                    }
                    HStack {
                        Text("Est. notional")
                        Spacer()
                        Text(estNotional.asMoney()).monospacedDigit()
                    }
                    HStack {
                        Text("Cash available")
                        Spacer()
                        Text(store.portfolio.cash.asMoney()).monospacedDigit()
                    }
                }

                Section {
                    Button {
                        confirm = true
                    } label: {
                        HStack {
                            Spacer()
                            Text(side == .buy ? "Review Buy" : "Review Sell")
                                .font(.headline)
                            Spacer()
                        }
                    }
                    .buttonStyle(.borderedProminent)
                    .tint(side == .buy ? .blue : .orange)
                    .disabled(qty <= 0 || (type == .limit && (limitPrice ?? 0) <= 0))
                }
            }
            .navigationTitle("Trade")
            .navigationBarTitleDisplayMode(.inline)
            .toolbar {
                ToolbarItem(placement: .topBarLeading) {
                    Button("Close") { dismiss() }
                }
            }
            .confirmationDialog("Confirm Order", isPresented: $confirm, titleVisibility: .visible) {
                Button(side == .buy ? "Place Buy" : "Place Sell", role: .none) {
                    let req = TradeRequest(symbol: symbol, side: side, type: type, quantity: qty, limitPrice: type == .limit ? limitPrice : nil)
                    store.placeOrder(req)
                    dismiss()
                }
                Button("Cancel", role: .cancel) {}
            } message: {
                Text("\(side.rawValue) \(qty.asQty()) \(symbol) • \(type.rawValue)\(type == .limit ? " @ \(estPrice.asMoney())" : "")\nEst. \(estNotional.asMoney())")
            }
        }
    }
}

struct PortfolioView: View {
    @EnvironmentObject var store: TradingStore
    @State private var selectedSymbol: String? = nil
    @State private var showTradeSheet: Bool = false

    var body: some View {
        NavigationStack {
            List {
                Section {
                    PortfolioHeader(snapshot: store.portfolio)
                }

                Section("Positions") {
                    if store.portfolio.positions.isEmpty {
                        Text("No positions yet. Place a trade from Markets.")
                            .foregroundStyle(.secondary)
                    } else {
                        ForEach(store.portfolio.positions) { pos in
                            Button {
                                selectedSymbol = pos.symbol
                                showTradeSheet = true
                            } label: {
                                PositionRow(position: pos)
                            }
                            .buttonStyle(.plain)
                        }
                    }
                }
            }
            .navigationTitle("Portfolio")
            .toolbar {
                ToolbarItem(placement: .topBarTrailing) {
                    Button {
                        store.refreshPortfolio()
                    } label: {
                        Label("Refresh", systemImage: "arrow.clockwise")
                    }
                }
            }
            .sheet(isPresented: $showTradeSheet) {
                if let sym = selectedSymbol {
