                            OrderRow(order: o)
                        }
                    }
                }
            }
            .navigationTitle("Orders")
        }
    }
}

struct OrderRow: View {
    let order: Order

    var body: some View {
        HStack {
            VStack(alignment: .leading, spacing: 4) {
                Text("\(order.side.rawValue) \(order.symbol)")
                    .font(.headline)
                Text("\(order.type.rawValue) • Qty \(order.quantity.asQty())\(order.type == .limit ? " @ \((order.limitPrice ?? 0).asMoney())" : "")")
                    .font(.caption)
                    .foregroundStyle(.secondary)
                Text(order.createdAt.formatted(date: .abbreviated, time: .standard))
                    .font(.caption2)
                    .foregroundStyle(.secondary)
            }
            Spacer()
            VStack(alignment: .trailing, spacing: 4) {
                Text(order.status.rawValue)
                    .font(.caption)
                    .padding(.horizontal, 8)
                    .padding(.vertical, 4)
                    .background(statusColor(order.status).opacity(0.15), in: Capsule())
                    .foregroundStyle(statusColor(order.status))
                if let px = order.avgFillPrice, order.status == .filled {
                    Text("Fill \(px.asMoney())")
                        .font(.caption)
                        .monospacedDigit()
                        .foregroundStyle(.secondary)
                } else {
                    Text(order.status == .rejected ? "Rejected" : "—")
                        .font(.caption)
                        .foregroundStyle(.secondary)
                }
            }
        }
        .padding(.vertical, 2)
    }

    private func statusColor(_ s: OrderStatus) -> Color {
        switch s {
        case .filled: return .green
        case .pending: return .blue
        case .rejected: return .red
        case .cancelled: return .secondary
        }
    }
}

struct SettingsView: View {
    @EnvironmentObject var store: TradingStore

    @State private var baseURLText: String = "https://api.example.com"
    @State private var apiKeyText: String = ""
    @State private var apiSecretText: String = ""
    @State private var pinnedText: String = ""
    @State private var showSecret: Bool = false

    private let keyApiKey = "trading.apiKey"
    private let keyApiSecret = "trading.apiSecret"
    private let keyBaseURL = "trading.baseURL"
    private let keyPinned = "trading.pinned"

    var body: some View {
        NavigationStack {
            Form {
                Section("Mode") {
                    Toggle(isOn: Binding(
                        get: { !store.isUsingMock },
                        set: { useReal in
                            if useReal {
                                applyRealConfig()
                            } else {
                                store.useMock()
                            }
                        }
                    )) {
                        Text("Use Real API")
                    }
                    Text(store.isUsingMock ? "Mock engine enabled (instant deployment)." : "Real API enabled.")
                        .font(.caption)
                        .foregroundStyle(.secondary)
                }

                Section("API Configuration") {
                    TextField("Base URL", text: $baseURLText)
                        .textInputAutocapitalization(.never)
                        .autocorrectionDisabled()
                        .keyboardType(.URL)

                    TextField("API Key", text: $apiKeyText)
                        .textInputAutocapitalization(.never)
                        .autocorrectionDisabled()

                    HStack {
                        Group {
                            if showSecret {
                                TextField("API Secret", text: $apiSecretText)
                            } else {
                                SecureField("API Secret", text: $apiSecretText)
                            }
                        }
                        .textInputAutocapitalization(.never)
                        .autocorrectionDisabled()

                        Button {
                            showSecret.toggle()
                        } label: {
                            Image(systemName: showSecret ? "eye.slash" : "eye")
                        }
                        .buttonStyle(.plain)
                    }

                    TextField("Pinned SPKI SHA256 (base64, optional)", text: $pinnedText)
                        .textInputAutocapitalization(.never)
                        .autocorrectionDisabled()

                    Button("Save to Keychain") {
                        save()
                    }
                    .buttonStyle(.borderedProminent)

                    Button("Load from Keychain") {
                        load()
                    }
                    .buttonStyle(.bordered)

                    Button("Apply Real API Config") {
                        applyRealConfig()
                    }
                    .buttonStyle(.bordered)
                    .disabled(!canApplyReal)
                }

                Section("Security") {
                    Text("All requests are signed with HMAC-SHA256 and sent over TLS. Optional certificate pinning supported via SPKI hash.")
                        .font(.caption)
                        .foregroundStyle(.secondary)
                }
            }
            .navigationTitle("Settings")
            .onAppear { load() }
        }
    }

    private var canApplyReal: Bool {
        URL(string: baseURLText) != nil && !apiKeyText.isEmpty && !apiSecretText.isEmpty
    }

    private func save() {
        _ = Keychain.shared.set(Data(apiKeyText.utf8), for: keyApiKey)
        _ = Keychain.shared.set(Data(apiSecretText.utf8), for: keyApiSecret)
        UserDefaults.standard.set(baseURLText, forKey: keyBaseURL)
        UserDefaults.standard.set(pinnedText, forKey: keyPinned)
    }

    private func load() {
        if let d = Keychain.shared.get(keyApiKey), let s = String(data: d, encoding: .utf8) { apiKeyText = s }
        if let d = Keychain.shared.get(keyApiSecret), let s = String(data: d, encoding: .utf8) { apiSecretText = s }
        baseURLText = UserDefaults.standard.string(forKey: keyBaseURL) ?? baseURLText
        pinnedText = UserDefaults.standard.string(forKey: keyPinned) ?? pinnedText
    }

    private func applyRealConfig() {
        guard let url = URL(string: baseURLText), !apiKeyText.isEmpty, !apiSecretText.isEmpty else { return }
        let pinned = pinnedText.trimmingCharacters(in: .whitespacesAndNewlines)
        store.configureAPI(baseURL: url, apiKey: apiKeyText, apiSecret: apiSecretText, pinnedSPKISHA256: pinned.isEmpty ? nil : pinned)
    }
}

